INSERT INTO `defects` VALUES (467,NULL,'2026-03-19 01:43:38.745122','','2026-03-19 01:43:38.745122','未知位置','medium','pending','cable_defectueux','2026-03-19 01:43:38.745122','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.8555,\"bbox_xyxy\":[269.5,243.25,653.0,350.5],\"is_defect\":true}]','/api/images/stream1_frame_4.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.709,\"bbox_xyxy\":[457.5,216.88,581.0,437.0],\"is_defect\":true},{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.5518,\"bbox_xyxy\":[160.12,228.12,293.5,412.0],\"is_defect\":true}]','data:image/jpeg;base64,',0.8555,NULL,'D:/Desktop/example_responses/stream1_frame_4.jpg','1. 缺陷原因分析  \n• 可见光图像中，电缆表面存在明显断股和金属丝裸露，属于机械损伤。红外图像显示该区域温度分布异常，局部热点（最高36.8°C）与周围（平均29.3°C）存在温差，表明存在接触不良或电阻增大的问题，进一步证实了电缆缺陷的存在。  \n\n2. 风险评估  \n• 当前风险等级：中等。  \n• 电缆断股可能导致载流能力下降，局部过热可能引发绝缘老化、短路甚至火灾风险，尤其在高负荷运行时风险加剧。  \n\n3. 处理建议  \n• 立即安排停电检修，对受损电缆段进行更换或修复。  \n• 结合红外检测结果，确认缺陷范围并评估是否影响邻近设备。','4. 维修方案  \n• 切断电源，隔离故障电缆段。  \n• 采用同规格电缆进行更换，确保接头连接牢固、绝缘良好。  \n• 修复后进行红外测温与电气性能测试，确保恢复正常。  \n\n5. 预防措施  \n• 定期开展红外巡检，重点关注电缆接头与易受外力损伤区域。  \n• 加强电缆通道防护，避免外力破坏。  \n• 优化检测模型，结合多模态数据提升缺陷识别准确性。',NULL,NULL,NULL,NULL);
INSERT INTO `defects` VALUES (468,NULL,'2026-03-19 01:43:43.953014','','2026-03-19 01:43:43.953014','未知位置','medium','pending','cable_defectueux','2026-03-19 01:43:43.953014','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.6636,\"bbox_xyxy\":[117.19,45.47,660.0,422.0],\"is_defect\":true}]','/api/images/stream1_frame_5.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.7954,\"bbox_xyxy\":[44.06,86.5,154.0,173.12],\"is_defect\":true}]','data:image/jpeg;base64,',0.6636,NULL,'D:/Desktop/example_responses/stream1_frame_5.jpg','1. 缺陷原因分析\n• 可见光图像显示大量电缆杂乱缠绕，部分电缆外皮破损，存在明显物理损伤。红外图像中，检测框区域（对应可见光图中电缆密集区）出现局部热点，显示异常温升，表明该区域存在接触不良或过载导致的发热现象，与电缆缺陷特征相符。\n\n2. 风险评估\n• 当前风险等级：中等。电缆绝缘层破损可能导致短路、漏电，引发火灾或触电事故。局部过热可能加速绝缘老化，存在安全隐患。\n\n3. 处理建议\n• 立即对检测区域电缆进行断电检查，确认破损位置及发热原因。对受损电缆进行更换或修复，规范布线，消除安全隐患。','4. 维修方案\n• 切断相关电源，拆除破损电缆段，更换为符合规格的绝缘电缆。重新整理布线，使用线槽或穿管保护，确保线路安全整洁。\n\n5. 预防措施\n• 定期开展电缆巡检，重点检查外皮完整性及接头处温度。加强电缆敷设管理，避免交叉缠绕。对老旧线路进行升级改造，提升整体安全水平。',NULL,NULL,NULL,NULL);
INSERT INTO `defects` VALUES (469,NULL,'2026-03-19 01:43:47.664368','','2026-03-19 01:43:47.664368','未知位置','medium','pending','cable_defectueux','2026-03-19 01:43:47.664368','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.8838,\"bbox_xyxy\":[101.75,327.5,542.5,407.5],\"is_defect\":true}]','/api/images/stream1_frame_2.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.458,\"bbox_xyxy\":[468.0,246.88,599.0,327.0],\"is_defect\":true}]','data:image/jpeg;base64,',0.8838,NULL,'D:/Desktop/example_responses/stream1_frame_2.jpg','1. 缺陷原因分析  \n• 经图像分析，未发现明显缺陷，本次为误判。可见光图像中电缆外观完整，无破损、断股或老化迹象；红外图像显示电缆区域温度分布均匀，无异常热点或冷点，最高温度37.5℃，处于正常运行范围。检测模型可能因背景杂乱（如植被干扰）或热成像中非电气部件的热辐射混淆而产生误判。  \n\n2. 风险评估  \n• 当前风险等级：无风险，设备状态正常。  \n\n3. 处理建议  \n• 建议将本条记录标记为误报。','4. 维修方案  \n• 无需维修。  \n\n5. 预防措施  \n• 持续优化检测模型，减少误判率。',_binary '',NULL,NULL,NULL),(470,NULL,'2026-03-19 01:43:50.959762','','2026-03-19 01:43:50.959762','未知位置','medium','pending','cable_defectueux','2026-03-19 01:43:50.959762','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.8809,\"bbox_xyxy\":[18.12,318.25,637.0,401.25],\"is_defect\":true}]','/api/images/stream1_frame_6.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.7832,\"bbox_xyxy\":[17.34,74.31,135.12,164.38],\"is_defect\":true},{\"class_id\":2,\"class_name\":\"class_2\",\"score\":0.5,\"bbox_xyxy\":[31.91,85.94,123.0,151.38],\"is_defect\":true}]','data:image/jpeg;base64,',0.8809,NULL,'D:/Desktop/example_responses/stream1_frame_6.jpg','1. 缺陷原因分析  \n• 经图像分析，未发现明显缺陷，本次为误判。可见光图像中电缆呈正常悬空状态，无破损、变形或异常连接点；红外图像显示设备整体温度分布均匀，无局部过热现象，检测框内的高温区域（如左上角）与电缆无关，可能为设备内部元件或热源干扰。  \n\n2. 风险评估  \n• 当前风险等级：无风险，设备状态正常。  \n\n3. 处理建议  \n• 建议将本条记录标记为误报。','4. 维修方案  \n• 无需维修。  \n\n5. 预防措施  \n• 持续优化检测模型，减少误判率。',_binary '',NULL,NULL,NULL),(471,NULL,'2026-03-19 01:43:57.518778','','2026-03-19 01:43:57.518778','未知位置','medium','pending','cable_defectueux','2026-03-19 01:43:57.518778','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.8076,\"bbox_xyxy\":[-13.12,170.75,626.0,434.5],\"is_defect\":true}]','/api/images/stream1_frame_9.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.5488,\"bbox_xyxy\":[338.0,124.88,629.5,305.25],\"is_defect\":true}]','data:image/jpeg;base64,',0.8076,NULL,'D:/Desktop/example_responses/stream1_frame_9.jpg','1. 缺陷原因分析  \n• 可见光图像显示电缆外皮存在明显破损，局部金属导体裸露，且有烧蚀痕迹，表明曾发生过过热或电弧放电。  \n• 红外图像中，该电缆区域呈现明显热点（最高温达43.0°C），与周围低温区域形成显著温差，说明存在接触不良或局部电阻增大的故障。  \n• 检测模型识别结果与图像特征高度吻合，置信度较高，确认为真实缺陷。  \n\n2. 风险评估  \n• 当前风险等级：中等风险。  \n• 电缆破损可能导致绝缘失效，引发短路、接地故障或火灾。  \n• 热点持续存在将加速绝缘老化，增加故障扩散风险。  \n\n3. 处理建议  \n• 立即对该电缆进行停电隔离，避免进一步损坏。  \n• 详细检查该段电缆及连接点，确认故障范围。  \n• 对受损部位进行更换或修复，恢复绝缘性能。','4. 维修方案  \n• 停电后，拆除损坏电缆段，更换为同规格耐候型电缆。  \n• 重新制作电缆接头，采用热缩套管或密封胶进行绝缘处理。  \n• 修复完成后，进行绝缘电阻测试和红外测温，确保无异常。  \n\n5. 预防措施  \n• 定期开展红外巡检，重点关注电缆接头、分支点等易发热部位。  \n• 加强电缆敷设环境管理，避免机械损伤和潮湿腐蚀。  \n• 建立缺陷数据库，结合AI模型优化识别精度，降低误报率。',NULL,NULL,NULL,NULL);
INSERT INTO `defects` VALUES (472,NULL,'2026-03-19 01:44:00.831611','','2026-03-19 01:44:00.831611','未知位置','medium','pending','cable_defectueux','2026-03-19 02:12:22.270261','[{\"class_id\":0,\"class_name\":\"cable_defectueux\",\"score\":0.9121,\"bbox_xyxy\":[12.81,289.75,576.5,411.25],\"is_defect\":true}]','/api/images/stream1_frame_3.jpg','data:image/jpeg;base64,','[{\"class_id\":1,\"class_name\":\"class_1\",\"score\":0.4941,\"bbox_xyxy\":[55.59,301.0,180.5,391.5],\"is_defect\":true},{\"class_id\":0,\"class_name\":\"class_0\",\"score\":0.4272,\"bbox_xyxy\":[251.5,207.75,306.5,341.0],\"is_defect\":true}]','data:image/jpeg;base64,',0.9121,NULL,'D:/Desktop/example_responses/stream1_frame_3.jpg','1. 缺陷原因分析  \n• 经图像分析，未发现明显缺陷，本次为误判。可见光图像中电缆外观完整，无破损、断股或异常变形；红外图像显示设备整体温度分布均匀，无异常热点，最高温37.5℃，处于正常范围，未见局部过热现象。检测模型在可见光图像中将正常电缆误判为“cable_defectueux”，且红外检测框所标位置与可见光图像中的电缆位置不对应，存在定位偏差。  \n\n2. 风险评估  \n• 当前风险等级：无风险，设备状态正常。  \n\n3. 处理建议  \n• 建议将本条记录标记为误报。','4. 维修方案  \n• 无需维修。  \n\n5. 预防措施  \n• 持续优化检测模型，减少误判率。',_binary '','定位框偏移/框到无关背景','[\n    {\"tYears\": 0, \"severity\": \"low\"},\n    {\"tYears\": 1, \"severity\": \"medium\"},\n    {\"tYears\": 2, \"severity\": \"high\"},\n    {\"tYears\": 3, \"severity\": \"critical\"}\n  ]',NULL);
